%PMSAMPLE Sample Prediction Model Sessionecho onclc%    ==========================================================%    PMSAMPLE        %    ==========================================================%    unianal   - ACF, PACF and GPAC for single time series.%    multianal - Impulse response, residual ACF and GPAC's for dual time series.%    newbjtf   - Create a Box and Jenkins transfer function model.%    estimate  - General parameter estimation framework.%    pmodaic   - AIC for a fitted model.%    newregr   - Create a linear regression model.%    newarmax  - Create an ARMAX model.%    predict   - Use a prediction model to predict a time series.%    TIME SERIES ANALYSIS:%    Using the above functions prediction models are developed%    for two different set of time series.  One set consists of%    a mining factor (output variable) and a potential explanatory%    variable labeled univret_eq.  The second set consists of%    simulated data.pause % Strike any key to continue...clc%    DEFINING THE  PROBLEM%    =====================%    The .mat file FACTORTST contains matrices%    u and y.  The u matrix contains the prediction model inputs,%    which are labeled univret_eq.%    The y matrix contains the corresponding desired model ouputs, %    which are mining factors.% Load in the data fileload factortst% Plot datame = 'PMSAMPLE';fig1 = setfig(me);subplot(2,1,1), plot(u)title('Input Sequence')subplot(2,1,2), plot(y)title('Output Sequence')pause % Strike any key to analyze the data...clc% Find the acf, pacf and gpac for the y sequence.[yacf,ypacf,ygpac] = uniAnal(y,20,10);% It appears that this data is almost white, with an acf% that is almost an impulse function.  Select the figure% named "ACF and PACF" to see the autocorrelation function.% The figure named "GPAC Array" displays the GPAC% for this data. The first row contains small% values, also indicating a white sequence.pause % Strike any key to continue analysis...clc% Find the impulse response between u and y, the residual% autocorrelation, and the GPAC array for each.  In the% figure labeled "Impulse Response and Residual ACF" the% impulse response appears to be a single value at a% lag of zero.  This indicates little dynamics between% the two variables.  A simple regression model might% work fine here.[g,rv,g_gpac,h_gpac] = multiAnal(u,y);pause % Strike any key to model the data...clc% For the first prediction model of this data we will.% use the Box and Jenkins transfer function model.  The% function NEWBJTF creates the model structure.  Here% we have first order numerators and denominators for% each transfer function.  The model is in the form%    y(t) = G u(t) + H e(t)% where G is a transfer function with numerator pmod.b% and denomitor pmod.f, H is a transfer function with% numerator pmod.c and denominator pmod.d. We are% using a zero delay between u and y because the% impulse response shows no delay (the largest % value shows at zero lag).pmod = newbjtf(1,1,1,1,0);pause % Strike any key to estimate the model parameters...clc% We estimate the model parameters for 50 iterations% and displaying the results every 20 iterations.pmod.estimParam.epochs = 50;pmod.estimParam.show = 20;pmod = estimate(pmod,y,u);pause % Strike any key to display the results...clc%    TESTING THE PREDICTION MODEL%    ===========================y2 = predict(pmod,y,u);ind = 1:length(y2);fig1 = setfig(me);plot(ind,y,'o',ind,y2,'x')legend('y(t)','yhat(t)')% These are the final parameter valuespmod.b{1}pmod.f{1}pmod.c{1}pmod.d{1}pause % Strike any key to start second test...clc% For the second prediction model of this data we will.% use the linear regression model.  The% function NEWREGR creates the model structure.  Here% we have a single variable regression, since there% is only one row in u. pmod.b contains the regression% parameters.pmod = newregr(1);pause % Strike any key to estimate the model parameters...clc% We estimate the model parameters for 50 iterations% but the regression model will always converge after% one iteration.pmod.estimParam.epochs = 50;pmod.estimParam.show = 20;pmod = estimate(pmod,y,u);% Note that the mean square error for the regression model% is almost the same as that for the bjtf model (0.00148% compared to 0.00139).  As we suspected from the % impulse response, the dynamics here are not % significant.pause % Strike any key to display the results...clc%    TESTING THE PREDICTION MODEL%    ===========================y2 = predict(pmod,y,u);ind = 1:length(y2);fig1 = setfig(me);plot(ind,y,'o',ind,y2,'x')legend('y(t)','yhat(t)')% These are the final parameter valuespmod.b{1}pause % Strike any key to start third test...clc% For the third prediction model of this data we will.% use the ARMAX model.  The function NEWARMAX% creates the model structure.  Here% we have first order numerators and denominators for% each transfer function.  The model is in the form%    y(t) = G u(t) + H e(t)% where G is a transfer function with numerator pmod.b% and denomitor pmod.a, H is a transfer function with% numerator pmod.c and denominator pmod.a. We are% using a zero delay between u and y because the% impulse response shows no delay (the largest % value shows at zero lag).  Note that the ARMAX% model has one less parameter to set than the% BJTF model, since the denominators of G and % H are both pmod.a.pmod = newarmax(1,1,1,0);pause % Strike any key to estimate the model parameters...clc% We estimate the model parameters for 50 iterations% and display the results every 20 iterations.pmod.estimParam.epochs = 50;pmod.estimParam.show = 20;pmod = estimate(pmod,y,u);% Note that the mean square error for the armax model% is almost the same as that for the bjtf model (0.001389% compared to 0.001388).   pause % Strike any key to display the results...clc%    TESTING THE PREDICTION MODEL%    ===========================y2 = predict(pmod,y,u);ind = 1:length(y2);fig1 = setfig(me);plot(ind,y,'o',ind,y2,'x')legend('y(t)','yhat(t)')% These are the final parameter valuespmod.a{1}pmod.b{1}pmod.c{1}pause % Strike any key to display the results...clc%    DEFINING THE  SECOND PROBLEM%    =============================%    Here we create some simulated data from%    a known model.  %    The u matrix contains the prediction model inputs,%    and the y matrix contains the corresponding desired model  %    ouputs.% Create the datae = randn(1,2000)*0.2;u = randn(1,2000);y = filter([0 2],[1 .5],u) + filter([1 .25],[1 -.8],e);% Plot the datafig1 = setfig(me);subplot(2,1,1), plot(u)title('Input Sequence')subplot(2,1,2), plot(y)title('Output Sequence')pause % Strike any key to analyze the data...clc% Find the impulse response between u and y, the residual% autocorrelation, and the GPAC array for each.  In the% figure labeled "Impulse Response and Residual ACF" the% impulse response appears to a simple damped oscillation.% This indicates a possible first order model with a % negative parameter.  The first nonzero value of the% impulse response is at a lag of one, which indicates% a delay of one in the model.  The GPAC for the G% transfer function verifies this analysis.  The large% values across the first row indicate the delay of one.% The sequence of constant values in the first column% after the first row indicate a first order % denominator.[g,rv,g_gpac,h_gpac] = multiAnal(u,y);pause % Strike any key to model the data...clc% For the prediction model of this data we will.% use the Box and Jenkins transfer function model.  The% function NEWBJTF creates the model structure.  Here% we have first order numerators and denomitors for% each transfer function, except for the zero order% numerator for the G transfer function.pmod = newbjtf(0,1,1,1,1);pause % Strike any key to estimate the model parameters...clc% We estimate the model parameters for 50 iterations% and displaying the results every 20 iterations.pmod.estimParam.epochs = 50;pmod.estimParam.show = 20;[pmod,trec,stat] = estimate(pmod,y,u);pause % Strike any key to display the results...clc%    TESTING THE PREDICTION MODEL%    ===========================y2 = predict(pmod,y,u);ind = 1:length(y2);fig1 = setfig(me);plot(ind,y,'o',ind,y2,'x')legend('y(t)','yhat(t)')% These are the final parameter estimates, their standard deviations% and the true values.[pmod.b{1} pmod.f{1} pmod.c{1} pmod.d{1}][stat.stdx' ][ 2  0.5 .25 -.8]% This is the AIC of the fitted model.  This can be used% to compare different models.aic = pmodaic(pmod,y,u)echo offdisp('End of PMSAMPLE')